import threading
import time


def worker(name):
    time.sleep(0.01)
    return name


class Runner:
    def __init__(self):
        # BUG: single Thread instance, started twice
        self.t = threading.Thread(target=worker, args=('w',))

    def run_twice(self):
        self.t.start()
        self.t.join()
        self.t.start()
        self.t.join()


def main():
    runner = Runner()
    runner.run_twice()
    print('done')


if __name__ == '__main__':
    main()
